assign_dada2 <- function(
  physeq = NULL,
  ref_fasta = NULL,
  seq2search = NULL,
  min_bootstrap = 0.5,
  tryRC = FALSE,
  taxa_ranks = c(
    "Kingdom",
    "Phylum",
    "Class",
    "Order",
    "Family",
    "Genus",
    "Species",
    "taxId"
  ),
  use_assignSpecies = TRUE,
  trunc_absent_ranks = FALSE,
  nproc = 1,
  suffix = "",
  verbose = TRUE,
  seq_at_one_time = 2000,
  allowMultiple = FALSE,
  from_sintax = FALSE
) {
  if (is.null(physeq)) {
    if (is.null(seq2search)) {
      stop("You must specify either physeq or seq2search args.")
    }
  } else {
    verify_pq(physeq)
    seq2search <- physeq@refseq
  }
  if (!from_sintax) {
    if (.detect_tax_format(ref_fasta) != "unite") {
      .validate_ref_format(ref_fasta, "dada2", "assign_dada2")
    }
  }

  if (from_sintax) {
    Biostrings::writeXStringSet(
      format2dada2(fasta_db = ref_fasta),
      "temp_taxo.fasta"
    )
    ref_fasta_taxo <- "temp_taxo.fasta"
  } else {
    ref_fasta_taxo <- ref_fasta
  }
  taxtab <- dada2::assignTaxonomy(
    seqs = seq2search,
    refFasta = ref_fasta_taxo,
    taxLevels = taxa_ranks,
    multithread = nproc,
    minBoot = min_bootstrap * 100,
    tryRC = tryRC,
    verbose = verbose,
    outputBootstraps = FALSE
  )

  taxtab <- as.data.frame(taxtab)
  rownames(taxtab) <- names(seq2search)

  if (use_assignSpecies) {
    Biostrings::writeXStringSet(
      format2dada2_species(fasta_db = ref_fasta),
      "temp_species.fasta"
    )

    GS <- dada2::assignSpecies(
      seqs = seq2search,
      refFasta = "temp_species.fasta",
      allowMultiple = allowMultiple,
      n = seq_at_one_time,
      tryRC = tryRC
    )

cmd_sintax <-
  paste0(
    " --sintax ",
    shQuote(temporary_fasta_file),
    " --db ",
    shQuote(ref_fasta),
    " --tabbedout ",
    shQuote(output_taxo_file),
    " --threads ",
    nproc,
    " ",
    cmd_args
  )

if (behavior == "return_cmd") {
  if (!keep_temporary_files) {
    unlink(temporary_fasta_file)
  }
  return("sintax" = paste0(vsearchpath, " ", cmd_sintax))
}

vsearch_output <- system2(
  vsearchpath,
  args = cmd_sintax,
  stdout = TRUE,
  stderr = TRUE
)
vsearch_status <- attr(vsearch_output, "status")

if (!is.null(vsearch_status) && vsearch_status != 0) {
  if (!keep_temporary_files) {
    unlink(temporary_fasta_file)
    unlink(output_taxo_file)
  }
  stop(
    "Vsearch sintax failed with status ",
    vsearch_status,
    ".\n",
    paste(vsearch_output, collapse = "\n")
  )
}

if (
  !file.exists(output_taxo_file) ||
    file.info(output_taxo_file)$size == 0
) {
  warning("No taxonomic assignation were made.")
  if (!keep_temporary_files) {
    unlink(temporary_fasta_file)
    unlink(output_taxo_file)
  }
  if (behavior == "add_to_phyloseq") {
    return(physeq)
  } else {
    return(NULL)
  }
}
