library(roxygen2)
# Parse all R files and find exported fns without @return
files <- list.files('R', pattern = '\\\\.R$', full.names = TRUE)
issues <- c()
for (f in files) {
  blocks <- parse_file(f)
  for (b in blocks) {
    tags <- b\$tags
    tag_names <- sapply(tags, function(t) t\$tag)
    has_export <- 'export' %in% tag_names
    has_return <- 'return' %in% tag_names
    if (has_export && !has_return) {
      name_tag <- tags[tag_names == 'name']
      fn_name <- if (length(name_tag) > 0) name_tag[[1]]\$val else 'unknown'
      issues <- c(issues, paste0(basename(f), ': ', fn_name))
    }
  }
}
cat(length(issues), 'exported functions missing @return\n')
if (length(issues) > 0) cat(paste(issues, collapse='\n'), '\n')
" 2>/dev/null

Rscript -e "
library(roxygen2)
files <- list.files('R', pattern = '\\\\.R\$', full.names = TRUE)
issues <- c()
for (f in files) {
  blocks <- tryCatch(parse_file(f), error=function(e) list())
  for (b in blocks) {
    tags <- b\$tags
    tag_names <- sapply(tags, function(t) t\$tag)
    has_export <- 'export' %in% tag_names
    has_return <- 'return' %in% tag_names || 'inheritParams' %in% tag_names
    if (has_export && !has_return) {
      name_tag <- tags[tag_names == 'name']
      fn_name <- if (length(name_tag) > 0) name_tag[[1]]\$val else 'unknown'
      issues <- c(issues, paste0(basename(f), ': ', fn_name))
    }
  }
}
cat(length(issues), 'exported functions possibly missing @return\n')
if (length(issues) > 0) writeLines(issues)
"

